using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Agents.AI.ChatCompletion;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using OpenAI;

// --- Configuration -----------------------------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- DI & Services -----------------------------------------------------------

var services = new ServiceCollection();

services.AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));

services.AddChatClient(builder => builder
    .UseOpenAIChatClient(modelId, new OpenAIClient(apiKey)));

var sp = services.BuildServiceProvider();
var chatClient = sp.GetRequiredService<IChatClient>();
var logger = sp.GetRequiredService<ILogger<Program>>();

// --- Tools -------------------------------------------------------------------

var notebook = new Notebook();
var tools = new AITools(notebook);

// --- Agent -------------------------------------------------------------------

var agent = new ChatClientAgent(chatClient, new ChatClientAgentOptions
{
    Instructions = """
        You are a research agent. Your goal is to thoroughly research a topic
        provided by the user. Follow these steps:

        1. Break the topic into 2-3 focused search queries.
        2. Use the WebSearch tool for each query to gather information.
        3. Use the AddNote tool to save key findings as you go.
        4. After gathering enough information, use the GetNotes tool to review
           all your notes.
        5. Produce a final, well-structured summary with sections and bullet
           points. Cite sources where possible.

        Be thorough but concise. Prefer factual, verifiable information.
        """,
    DefaultChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 2048,
        Tools = [
            AIFunctionFactory.Create(tools.WebSearch),
            AIFunctionFactory.Create(tools.AddNote),
            AIFunctionFactory.Create(tools.GetNotes),
        ],
    },
});

// --- Main loop ---------------------------------------------------------------

Console.WriteLine("╔═══════════════════════════════════════╗");
Console.WriteLine("║       🔍 Research Agent               ║");
Console.WriteLine("║  Type a topic to research, or 'quit'  ║");
Console.WriteLine("╚═══════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Topic> ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    notebook.Clear();

    var history = new List<ChatMessage>
    {
        new(ChatRole.User, $"Research the following topic and provide a comprehensive summary:\n\n{topic}"),
    };

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine("\nResearching… (this may take a moment)\n");
    Console.ResetColor();

    try
    {
        var options = new AgentInvokeOptions { MaximumIterations = 10 };

        await foreach (var message in agent.InvokeStreamingAsync(history, options))
        {
            if (message.Role == ChatRole.Assistant && !string.IsNullOrWhiteSpace(message.Text))
            {
                Console.ForegroundColor = ConsoleColor.Green;
                Console.Write(message.Text);
                Console.ResetColor();
            }

            logger.LogDebug("Agent step: Role={Role}, ContentLength={Length}",
                message.Role, message.Text?.Length ?? 0);
        }

        Console.WriteLine("\n");
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"\nError: {ex.Message}\n");
        Console.ResetColor();
    }
}

Console.WriteLine("Goodbye!");

// =============================================================================
// Tool implementations
// =============================================================================

/// <summary>Stores research notes collected during an agent session.</summary>
sealed class Notebook
{
    private readonly List<string> _notes = [];

    public void Add(string note) => _notes.Add(note);
    public IReadOnlyList<string> GetAll() => _notes;
    public void Clear() => _notes.Clear();
}

/// <summary>Tools exposed to the research agent.</summary>
sealed class AITools
{
    private static readonly HttpClient Http = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
    };

    private readonly Notebook _notebook;

    public AITools(Notebook notebook) => _notebook = notebook;

    [Description("Search the web for information on a query. Returns a list of results with titles, snippets, and URLs.")]
    public async Task<string> WebSearch(
        [Description("The search query string")] string query)
    {
        Console.ForegroundColor = ConsoleColor.Yellow;
        Console.WriteLine($"  🔎 Searching: \"{query}\"");
        Console.ResetColor();

        try
        {
            var encoded = WebUtility.UrlEncode(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
            var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.UserAgent.ParseAdd("ResearchAgent/1.0");

            var response = await Http.SendAsync(request);
            response.EnsureSuccessStatusCode();
            var html = await response.Content.ReadAsStringAsync();

            var results = ParseDuckDuckGoResults(html);

            if (results.Count == 0)
                return $"No results found for \"{query}\".";

            var sb = new StringBuilder();
            sb.AppendLine($"Search results for \"{query}\":\n");
            for (var i = 0; i < results.Count; i++)
            {
                var r = results[i];
                sb.AppendLine($"{i + 1}. **{r.Title}**");
                sb.AppendLine($"   {r.Snippet}");
                sb.AppendLine($"   URL: {r.Url}");
                sb.AppendLine();
            }

            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Please try a different query.";
        }
    }

    [Description("Save a research note. Use this to record key findings during research.")]
    public string AddNote(
        [Description("The note content to save")] string note)
    {
        _notebook.Add(note);

        Console.ForegroundColor = ConsoleColor.Magenta;
        Console.WriteLine($"  📝 Note saved ({_notebook.GetAll().Count} total)");
        Console.ResetColor();

        return $"Note saved. You now have {_notebook.GetAll().Count} note(s).";
    }

    [Description("Retrieve all saved research notes to review before writing the summary.")]
    public string GetNotes()
    {
        var notes = _notebook.GetAll();
        if (notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        sb.AppendLine($"All research notes ({notes.Count}):\n");
        for (var i = 0; i < notes.Count; i++)
        {
            sb.AppendLine($"--- Note {i + 1} ---");
            sb.AppendLine(notes[i]);
            sb.AppendLine();
        }

        return sb.ToString();
    }

    /// <summary>Parses search result snippets from DuckDuckGo HTML response.</summary>
    private static List<SearchResult> ParseDuckDuckGoResults(string html)
    {
        var results = new List<SearchResult>();
        var resultMarker = "class=\"result__a\"";
        var snippetMarker = "class=\"result__snippet\"";
        var pos = 0;

        while (results.Count < 5)
        {
            var titleStart = html.IndexOf(resultMarker, pos, StringComparison.Ordinal);
            if (titleStart < 0) break;

            var title = ExtractTagContent(html, titleStart);
            var url = ExtractHref(html, titleStart);

            var snippetStart = html.IndexOf(snippetMarker, titleStart, StringComparison.Ordinal);
            var snippet = snippetStart >= 0 ? ExtractTagContent(html, snippetStart) : "";

            if (!string.IsNullOrWhiteSpace(title))
            {
                results.Add(new SearchResult(
                    StripHtml(title).Trim(),
                    StripHtml(snippet).Trim(),
                    url));
            }

            pos = snippetStart >= 0 ? snippetStart + 1 : titleStart + 1;
        }

        return results;
    }

    private static string ExtractTagContent(string html, int markerPos)
    {
        var tagClose = html.IndexOf('>', markerPos);
        if (tagClose < 0) return "";
        var start = tagClose + 1;
        var end = html.IndexOf('<', start);
        if (end < 0) return "";

        // Handle nested tags — grab until the closing tag of the same level
        var depth = 1;
        var i = start;
        while (i < html.Length && depth > 0)
        {
            if (html[i] == '<')
            {
                if (i + 1 < html.Length && html[i + 1] == '/')
                    depth--;
                else if (i + 1 < html.Length && html[i + 1] != '!')
                    depth++;
            }
            if (depth > 0) i++;
        }

        return html[start..i];
    }

    private static string ExtractHref(string html, int markerPos)
    {
        var hrefStart = html.LastIndexOf("href=\"", markerPos, Math.Min(markerPos, 500), StringComparison.Ordinal);
        if (hrefStart < 0)
        {
            hrefStart = html.IndexOf("href=\"", markerPos, StringComparison.Ordinal);
            if (hrefStart < 0) return "";
        }
        hrefStart += 6;
        var hrefEnd = html.IndexOf('"', hrefStart);
        if (hrefEnd < 0) return "";
        var rawUrl = html[hrefStart..hrefEnd];
        // DuckDuckGo wraps URLs in a redirect — extract the actual URL
        var uddg = rawUrl.IndexOf("uddg=", StringComparison.Ordinal);
        if (uddg >= 0)
        {
            var actualUrl = rawUrl[(uddg + 5)..];
            var amp = actualUrl.IndexOf('&');
            if (amp >= 0) actualUrl = actualUrl[..amp];
            return WebUtility.UrlDecode(actualUrl);
        }
        return rawUrl;
    }

    private static string StripHtml(string html)
    {
        var sb = new StringBuilder();
        var inTag = false;
        foreach (var c in html)
        {
            if (c == '<') inTag = true;
            else if (c == '>') inTag = false;
            else if (!inTag) sb.Append(c);
        }
        return WebUtility.HtmlDecode(sb.ToString());
    }

    private record SearchResult(string Title, string Snippet, string Url);
}

