/// <summary>Tools exposed to the research agent.</summary>
sealed class ResearchTools
{
    private static readonly HttpClient Http = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
    };

    private readonly Notebook _notebook;

    public ResearchTools(Notebook notebook) => _notebook = notebook;

    [Description("Search the web for information on a query. Returns a list of results with titles, snippets, and URLs.")]
    public async Task<string> WebSearch(
        [Description("The search query string")] string query)
    {
        Console.ForegroundColor = ConsoleColor.Yellow;
        Console.WriteLine($"  🔎 Searching: \"{query}\"");
        Console.ResetColor();

