    public string GetNotes()
    {
        var notes = _notebook.GetAll();
        if (notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        sb.AppendLine($"All research notes ({notes.Count}):\n");
        for (var i = 0; i < notes.Count; i++)
        {
            sb.AppendLine($"--- Note {i + 1} ---");
            sb.AppendLine(notes[i]);
            sb.AppendLine();
