105. // Tool implementations
106. // =============================================================================
107. 
108. /// <summary>Stores research notes collected during an agent session.</summary>
109. sealed class Notebook
110. {
111.     private readonly List<string> _notes = [];
112. 
113.     public void Add(string note) => _notes.Add(note);
114.     public IReadOnlyList<string> GetAll() => _notes;
115.     public void Clear() => _notes.Clear();
116. }
117. 
118. /// <summary>Tools exposed to the research agent.</summary>
119. sealed class ResearchTools
120. {
121.     private static readonly HttpClient Http = new()
122.     {
123.         Timeout = TimeSpan.FromSeconds(15),
124.     };
125. 
126.     private readonly Notebook _notebook;
127. 
128.     public ResearchTools(Notebook notebook) => _notebook = notebook;
129. 
130.     [Description("Search the web for information on a query. Returns a list of results with titles, snippets, and URLs.")]
131.     public async Task<string> WebSearch(
132.         [Description("The search query string")] string query)
133.     {
134.         Console.ForegroundColor = ConsoleColor.Yellow;
135.         Console.WriteLine($"  🔎 Searching: \"{query}\"");
136.         Console.ResetColor();
137. 
138.         try
139.         {
140.             var encoded = WebUtility.UrlEncode(query);
141.             var url = $"https://html.duckduckgo.com/html/?q={encoded}";
142.             var request = new HttpRequestMessage(HttpMethod.Get, url);
143.             request.Headers.UserAgent.ParseAdd("ResearchAgent/1.0");
144. 
145.             var response = await Http.SendAsync(request);
146.             response.EnsureSuccessStatusCode();
147.             var html = await response.Content.ReadAsStringAsync();
148. 
149.             var results = ParseDuckDuckGoResults(html);
150. 
151.             if (results.Count == 0)
152.                 return $"No results found for \"{query}\".";
153. 
154.             var sb = new StringBuilder();
155.             sb.AppendLine($"Search results for \"{query}\":\n");
156.             for (var i = 0; i < results.Count; i++)
157.             {
158.                 var r = results[i];
159.                 sb.AppendLine($"{i + 1}. **{r.Title}**");
160.                 sb.AppendLine($"   {r.Snippet}");
161.                 sb.AppendLine($"   URL: {r.Url}");
162.                 sb.AppendLine();
163.             }
164. 
165.             return sb.ToString();
166.         }
167.         catch (Exception ex)
168.         {
169.             return $"Search failed: {ex.Message}. Please try a different query.";
170.         }
171.     }
172. 
173.     [Description("Save a research note. Use this to record key findings during research.")]
174.     public string AddNote(
175.         [Description("The note content to save")] string note)
176.     {
177.         _notebook.Add(note);
178. 
179.         Console.ForegroundColor = ConsoleColor.Magenta;
180.         Console.WriteLine($"  📝 Note saved ({_notebook.GetAll().Count} total)");
181.         Console.ResetColor();
182. 
183.         return $"Note saved. You now have {_notebook.GetAll().Count} note(s).";
184.     }
185. 
186.     [Description("Retrieve all saved research notes to review before writing the summary.")]
187.     public string GetNotes()
188.     {
189.         var notes = _notebook.GetAll();
190.         if (notes.Count == 0)
191.             return "No notes saved yet.";
192. 
193.         var sb = new StringBuilder();
194.         sb.AppendLine($"All research notes ({notes.Count}):\n");
195.         for (var i = 0; i < notes.Count; i++)
196.         {
197.             sb.AppendLine($"--- Note {i + 1} ---");
198.             sb.AppendLine(notes[i]);
199.             sb.AppendLine();
200.         }
201. 
202.         return sb.ToString();
203.     }
204. 
205.     /// <summary>Parses search result snippets from DuckDuckGo HTML response.</summary>
206.     private static List<SearchResult> ParseDuckDuckGoResults(string html)
207.     {
208.         var results = new List<SearchResult>();
209.         var resultMarker = "class=\"result__a\"";
210.         var snippetMarker = "class=\"result__snippet\"";
211.         var pos = 0;
212. 
213.         while (results.Count < 5)
214.         {
215.             var titleStart = html.IndexOf(resultMarker, pos, StringComparison.Ordinal);
216.             if (titleStart < 0) break;
217. 
218.             var title = ExtractTagContent(html, titleStart);
219.             var url = ExtractHref(html, titleStart);
220. 
221.             var snippetStart = html.IndexOf(snippetMarker, titleStart, StringComparison.Ordinal);
222.             var snippet = snippetStart >= 0 ? ExtractTagContent(html, snippetStart) : "";
223. 
224.             if (!string.IsNullOrWhiteSpace(title))
225.             {
226.                 results.Add(new SearchResult(
227.                     StripHtml(title).Trim(),
228.                     StripHtml(snippet).Trim(),
229.                     url));
230.             }
231. 
232.             pos = snippetStart >= 0 ? snippetStart + 1 : titleStart + 1;
233.         }
234. 
235.         return results;
236.     }
237. 
238.     private static string ExtractTagContent(string html, int markerPos)
239.     {
240.         var tagClose = html.IndexOf('>', markerPos);
241.         if (tagClose < 0) return "";
242.         var start = tagClose + 1;
243. 
244.         var depth = 1;
245.         var i = start;
246.         while (i < html.Length && depth > 0)
247.         {
248.             if (html[i] == '<')
249.             {
250.                 if (i + 1 < html.Length && html[i + 1] == '/')
251.                     depth--;
252.                 else if (i + 1 < html.Length && html[i + 1] != '!')
253.                     depth++;
254.             }
255.             if (depth > 0) i++;
256.         }
257. 
258.         return html[start..i];
259.     }
260. 
261.     private static string ExtractHref(string html, int markerPos)
262.     {
263.         var hrefStart = html.LastIndexOf("href=\"", markerPos, Math.Min(markerPos, 500), StringComparison.Ordinal);
264.         if (hrefStart < 0)
265.         {
266.             hrefStart = html.IndexOf("href=\"", markerPos, StringComparison.Ordinal);
267.             if (hrefStart < 0) return "";
268.         }
269.         hrefStart += 6;
270.         var hrefEnd = html.IndexOf('"', hrefStart);
271.         if (hrefEnd < 0) return "";
272.         var rawUrl = html[hrefStart..hrefEnd];
273. 
274.         var uddg = rawUrl.IndexOf("uddg=", StringComparison.Ordinal);
275.         if (uddg >= 0)
276.         {
277.             var actualUrl = rawUrl[(uddg + 5)..];
278.             var amp = actualUrl.IndexOf('&');
279.             if (amp >= 0) actualUrl = actualUrl[..amp];
280.             return WebUtility.UrlDecode(actualUrl);
281.         }
282.         return rawUrl;
283.     }
284. 
285.     private static string StripHtml(string html)
286.     {
287.         var sb = new StringBuilder();
288.         var inTag = false;
289.         foreach (var c in html)
290.         {
291.             if (c == '<') inTag = true;
292.             else if (c == '>') inTag = false;
293.             else if (!inTag) sb.Append(c);
294.         }
295.         return WebUtility.HtmlDecode(sb.ToString());
296.     }
297. 
298.     private record SearchResult(string Title, string Snippet, string Url);
299. }
